I'm in the middle of a big rewrite from one hook to another.

the new one:
```ts web/breeze/components/CalcPage/hooks/useFetchedPackageSelection.ts
import { useState } from 'react';
import useSWRMutation from 'swr/mutation';
import {
  Cloud$Interest,
  Cloud$Package,
  Cloud$PackageOptionBattery_NEW,
  Cloud$PackageRequestBattery_NEW,
} from '@otovo/shared/types/cloudApi';
import { PackageState, PackageChange } from '../../../stores/Interest/type';
import { isEvChargerPackage } from '../../../lib/packageUtils';
import { Cloud$PurchaseModelCode } from '@otovo/shared/types/cloudEnums';
import useSWR from 'swr';

const getPackageOptions = async (
  url: string,
): Promise<Cloud$PackageOptionBattery_NEW[]> => {
  const response = await fetch(url, {
    method: 'GET',
  });

  if (!response.ok) {
    throw new Error(response.statusText);
  }

  return response.json();
};

async function updatePackage(
  url: string,
  { arg: packageRequest }: { arg: Cloud$PackageRequestBattery_NEW },
) {
  const response = await fetch(url, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(packageRequest),
  });

  if (!response.ok) {
    throw new Error('Failed to update package');
  }

  return response.json();
}

function getPackageOption(pkg: Cloud$Package): Cloud$PackageOptionBattery_NEW {
  return {
    main_hardware_type: 'battery_system',
    name: pkg.name, // e.g. standard_small
    product_name: pkg.product_name, // Pointer back to the product (e.g. standard)
    package_size: pkg.package_size, // e.g. small, medium, large
    with_ev_charger: isEvChargerPackage(pkg),
    minimum_battery_capacity: pkg.price.equipment.batteries[0]?.capacity || 0,
  };
}

function transformPackageOption(option: any): Cloud$PackageOptionBattery_NEW {
  return {
    main_hardware_type: 'battery_system',
    name: `custom_${option.battery_package_size}`,
    product_name: 'custom',
    package_size: option.battery_package_size,
    with_ev_charger: option.with_ev_charger,
    minimum_battery_capacity: option.minimum_battery_capacity,
  };
}

export function useFetchedPackageSelection(
  interest: Cloud$Interest,
): PackageState {
  const initialPakcages = interest.products
    .flatMap((p) => p.packages)
    .map(getPackageOption);

  const [selectedPackage, setSelectedPackage] = useState<Cloud$Package | null>(
    interest.active_shopping_cart_package,
  );
  const [selectedFinancingOption, setSelectedFinancingOption] = useState(
    interest.active_shopping_cart_package?.price.financing_options.find(
      (option) =>
        option.purchase_model_code === interest.default_purchase_model,
    ) ||
      interest.active_shopping_cart_package?.price.financing_options[0] ||
      null,
  );
  const { data: extraPackagesRaw, isLoading: isMutatingPackageOptions } =
    useSWR<Cloud$PackageOptionBattery_NEW[]>(
      `${process.env.NEXT_PUBLIC_OTOVOAPI_URL}/web/interests/${interest.id}/package_options/?main_hardware_type=battery_system`,
      getPackageOptions,
    );

  const { trigger: updatePackageMutation, isMutating: isMutatingPackage } =
    useSWRMutation(
      `${process.env.NEXT_PUBLIC_OTOVOAPI_URL}/web/interests/${interest.id}/update_package/`,
      updatePackage,
      {
        onSuccess: (pkg: Cloud$Package) => {
          setSelectedPackage(pkg);
          setSelectedFinancingOption(
            pkg.price.financing_options.find(
              (o) =>
                o.purchase_model_code ===
                selectedFinancingOption?.purchase_model_code,
            ) || pkg.price.financing_options[0],
          );
        },
      },
    );

  const changePackage = async (pkg: PackageChange) => {
    if (!selectedPackage) return;

    const currentConfig = getPackageOption(selectedPackage);
    const newConfiguration: Cloud$PackageRequestBattery_NEW = {
      ...currentConfig,
      [pkg.option]: pkg.value,
      name: `${currentConfig.product_name}_${pkg.value}`,
    };

    await updatePackageMutation(newConfiguration);
  };

  const changePurchaseModel = (code: Cloud$PurchaseModelCode) => {
    if (!selectedPackage) return;

    const newOption = selectedPackage.price.financing_options.find(
      (option) => option.purchase_model_code === code,
    );

    if (newOption) {
      setSelectedFinancingOption(newOption);
    }
  };
  const extraPackages = extraPackagesRaw?.map(transformPackageOption);

  return {
    selectedPackage,
    selectedFinancingOption,
    availablePackages: [...initialPakcages, ...(extraPackages || [])],
    isLoading: false,
    isMutating: isMutatingPackage || isMutatingPackageOptions,
    isPackageUpgraded: false, // Battery systems don't have the upgrade concept
    mainHardwareType: 'battery_system',
    changePackage,
    changePurchaseModel,
    productNames: new Set(initialPakcages.map((p) => p.product_name)),
    packageNames: new Set(initialPakcages.map((p) => p.name)),
  };
}
```


the old one:
```ts web/breeze/components/CalcPage/useShoppingCart.ts
import {
  Cloud$Interest,
  Cloud$PackageOption,
  Cloud$PackageRequest,
  Cloud$FinancingOption,
  Cloud$Package,
} from '@otovo/shared/types/cloudApi';
import {
  Cloud$PackageSize,
  Cloud$ProductName,
  Cloud$MainHardwareType,
  Cloud$PurchaseModelCode,
} from '@otovo/shared/types/cloudEnums';
import { useEffect, useReducer, useState } from 'react';
import useSWRMutation from 'swr/mutation';
import { useSWRConfig } from 'swr';
import { SurfaceConfiguration } from '../../stores/Interest/type';
import { useShoppingCartEmulator } from './useShoppingCartEmulator';
import {
  configurationReducer,
  initialConfiguration,
} from './shoppingCartConfigurationStore';
import { getPreferredConfiguration } from './preferredPackage';
import { getMainHardwareType } from '../../stores/Interest/utils/getMainHardwareType';
import {
  getPackageCacheKey,
  generateCacheKey,
} from './utils/getPackageCacheKey';
import { logChoiceSelection } from './utils/logging';

const getPackage = async (
  url: string,
  { arg: packageRequest }: { arg: Cloud$PackageRequest },
) => {
  const response = await fetch(url, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(packageRequest),
  });

  if (!response.ok) {
    throw new Error(response.statusText);
  }

  const shoppingCartPackage: Cloud$Package = await response.json();

  return { shoppingCartPackage, packageRequest };
};

const getPackageOptions = async (
  url: string,
  { arg: mainHardwareType }: { arg: Cloud$MainHardwareType },
) => {
  const response = await fetch(
    `${url}?main_hardware_type=${mainHardwareType}`,
    {
      method: 'GET',
    },
  );

  if (!response.ok) {
    throw new Error(response.statusText);
  }

  const packageOptions: Cloud$PackageOption[] = await response.json();
  return packageOptions;
};

export type PackageChange =
  | {
      option: 'pv_package_size' | 'battery_package_size';
      value: Cloud$PackageSize;
    }
  | {
      option: 'pv_product_name';
      value: Cloud$ProductName;
    }
  | {
      option: 'with_ev_charger' | 'with_battery';
      value: boolean;
    };

export type ShoppingCartReturn = {
  availableShoppingCartPackages: Cloud$PackageOption[];
  selectedShoppingCartPackage: Cloud$Package;
  selectedFinancingOption: Cloud$FinancingOption;
  surfaceConfigurationList: SurfaceConfiguration[];
  isLoadingPackage: boolean;
  isMutatingPackageOptions: boolean;
  isPackageUpgraded: boolean;
  mainHardwareType: Cloud$MainHardwareType;

  changePackage: (mutation: PackageChange) => Promise<void>;
  toggleSurface: (referenceId: string) => void;
  changePurchaseModel: (purchaseModelCode: Cloud$PurchaseModelCode) => void;
};

export function useShoppingCart(interest: Cloud$Interest): ShoppingCartReturn {
  const updatePackageUrl = `${process.env.NEXT_PUBLIC_OTOVOAPI_URL}/web/interests/${interest.id}/update_package/`;
  const { trigger: triggerPackageMutation } = useSWRMutation(
    updatePackageUrl,
    getPackage,
    {
      onSuccess: (data) => setNewConfiguration(data.packageRequest),
      populateCache: true,
    },
  );
  const [selectedShoppingCartPackage, setSelectedShoppingCartPackage] =
    useState(interest.active_shopping_cart_package);
  const [isLoadingPackage, setIsLoadingPackage] = useState(false);
  const { cache } = useSWRConfig();

  const [mainHardwareType] = useState<Cloud$MainHardwareType>(
    getMainHardwareType(interest),
  );
  const packageOptionsUrl = `${process.env.NEXT_PUBLIC_OTOVOAPI_URL}/web/interests/${interest.id}/package_options/`;
  const {
    trigger: triggerPackageOptions,
    data: packageOptionsData,
    isMutating: isMutatingPackageOptions,
  } = useSWRMutation(packageOptionsUrl, getPackageOptions, {});
  useEffect(() => {
    if (!triggerPackageOptions || !mainHardwareType) return;
    if (mainHardwareType !== 'battery_system') return; // TODO: remove when non-battery systems are supported
    triggerPackageOptions(mainHardwareType);
  }, [mainHardwareType, triggerPackageOptions]);

  // Cache the interest shopping cart package
  useEffect(() => {
    if (interest.active_shopping_cart_package && mainHardwareType) {
      const cacheKey = getPackageCacheKey(mainHardwareType, interest);
      const cachedData = cache.get(cacheKey);
      if (!cachedData) {
        cache.set(cacheKey, {
          data: { shoppingCartPackage: interest.active_shopping_cart_package },
        });
      }
    }
  }, [interest, cache, mainHardwareType]);

  const [{ currentConfiguration, previousConfiguration }, setNewConfiguration] =
    useReducer(configurationReducer, initialConfiguration(interest));
  const [purchaseModelCode, setPurchaseModelCode] = useState(
    interest.default_purchase_model,
  );

  // TODO: remove non-shopping cart calculations when all calculations are fetched via the shopping cart API.
  const emulatedHook = useShoppingCartEmulator(interest);
  if (mainHardwareType === 'pv_system') {
    return emulatedHook;
  }

  const availableShoppingCartPackages = packageOptionsData || [];

  const selectedFinancingOption =
    selectedShoppingCartPackage?.price.financing_options.find(
      (f) => f.purchase_model_code === purchaseModelCode,
    ) || selectedShoppingCartPackage?.price.financing_options[0];

  const changePackage = async (packageChange: PackageChange) => {
    const preferredPackage = getPreferredConfiguration({
      packageChange,
      availableConfigurations: availableShoppingCartPackages,
      currentConfiguration,
      previousConfiguration,
    });
    const cacheKey = generateCacheKey(preferredPackage);
    const cachedData = cache.get(cacheKey);

    if (cachedData) {
      setSelectedShoppingCartPackage(cachedData.data.shoppingCartPackage);
      triggerPackageMutation(preferredPackage);
    } else {
      // Set loading state only if we are not using cached data
      setIsLoadingPackage(true);
      const response = await triggerPackageMutation(preferredPackage);
      cache.set(cacheKey, { data: response });
      setSelectedShoppingCartPackage(response.shoppingCartPackage);
      setIsLoadingPackage(false);
    }
  };

  const isPackageUpgraded =
    previousConfiguration?.main_hardware_type === 'pv_system' &&
    currentConfiguration.main_hardware_type === 'pv_system' &&
    !previousConfiguration.with_battery &&
    currentConfiguration.with_battery &&
    previousConfiguration.pv_product_name ===
      currentConfiguration.pv_product_name &&
    previousConfiguration.pv_package_size ===
      currentConfiguration.pv_package_size;

  return {
    selectedShoppingCartPackage,
    selectedFinancingOption,
    availableShoppingCartPackages,
    isLoadingPackage,
    isMutatingPackageOptions: isMutatingPackageOptions,
    mainHardwareType: mainHardwareType,
    changePurchaseModel: (newPurchaseModelCode: Cloud$PurchaseModelCode) => {
      if (
        !selectedShoppingCartPackage?.price.financing_options
          .map((f) => f.purchase_model_code)
          .includes(newPurchaseModelCode)
      ) {
        throw Error(`Invalid purchase model code ${newPurchaseModelCode}`);
      }

      setPurchaseModelCode(newPurchaseModelCode);
      logChoiceSelection({
        choiceLabel: 'purchase model',
        changedTo: newPurchaseModelCode,
        experimentVersion: interest.experiment_version,
      });
    },
    changePackage,
    toggleSurface: () => {}, // Battery has no surfaces to toggle.
    surfaceConfigurationList: [],
    isPackageUpgraded,
  };
}
```



If you notice how `changePackage` used to be implemneted, we did stuff with cache key and additional loading states to update a package, preferring the cached version if it existed.

I think this is a bit overkill, and that SWR should handle this for us. In other words, I don't want to change the return shape of the hook, but I would like optimistic updates.

How things work right now, we're not using the existing cache if it exists, because `setSelectedPackage` is only called in the onSuccess of the useSWRMutation.

What are my options here?
Given your goal of leveraging SWR's caching and optimistic updates while maintaining the same return shape, you have several options:

1. Use `optimisticData` and `populateCache` in useSWRMutation:
```typescript
const { trigger: updatePackageMutation, isMutating: isMutatingPackage } =
  useSWRMutation(
    `${process.env.NEXT_PUBLIC_OTOVOAPI_URL}/web/interests/${interest.id}/update_package/`,
    updatePackage,
    {
      // Optimistically update the UI
      optimisticData: (currentData, { arg: newPackageRequest }) => {
        // Create an optimistic package based on the request
        return createOptimisticPackage(currentData, newPackageRequest);
      },
      // Update the cache immediately
      populateCache: true,
      // Revalidate after mutation
      revalidate: true,
      onSuccess: (pkg: Cloud$Package) => {
        setSelectedPackage(pkg);
        setSelectedFinancingOption(
          pkg.price.financing_options.find(
            (o) => o.purchase_model_code === selectedFinancingOption?.purchase_model_code,
          ) || pkg.price.financing_options[0],
        );
      },
    },
  );
```

2. Move the state management to SWR entirely using `useSWR` + `useSWRMutation`:
```typescript
const { data: selectedPackage, mutate } = useSWR(
  `${process.env.NEXT_PUBLIC_OTOVOAPI_URL}/web/interests/${interest.id}/current_package`,
  fetcher
);

const { trigger: updatePackageMutation } = useSWRMutation(
  `${process.env.NEXT_PUBLIC_OTOVOAPI_URL}/web/interests/${interest.id}/update_package/`,
  updatePackage,
  {
    onSuccess: (pkg: Cloud$Package) => {
      // Update the cache for the current package
      mutate(pkg, { revalidate: false });
    },
  },
);
```

3. Use optimistic updates with local state:
```typescript
const changePackage = async (pkg: PackageChange) => {
  if (!selectedPackage) return;

  const currentConfig = getPackageOption(selectedPackage);
  const newConfiguration: Cloud$PackageRequestBattery_NEW = {
    ...currentConfig,
    [pkg.option]: pkg.value,
    name: `${currentConfig.product_name}_${pkg.value}`,
  };

  // Create an optimistic package
  const optimisticPackage = createOptimisticPackage(selectedPackage, newConfiguration);

  // Update UI immediately
  setSelectedPackage(optimisticPackage);

  try {
    // Perform the actual update
    const result = await updatePackageMutation(newConfiguration);
    // Update with real data if different from optimistic update
    if (JSON.stringify(result) !== JSON.stringify(optimisticPackage)) {
      setSelectedPackage(result);
    }
  } catch (error) {
    // Revert to previous state on error
    setSelectedPackage(selectedPackage);
    throw error;
  }
};
```

Given your current setup, I'd recommend option 1 or 2. Option 1 maintains more similarity with your current code while adding optimistic updates. Option 2 would be a more "SWR-native" approach, letting SWR handle more of the state management.

The main benefit of using SWR's built-in features is that you get automatic cache invalidation, revalidation, and error handling without having to implement it yourself. It also handles race conditions better than manual implementations.

Do you have a preference among these approaches? I can elaborate more on any of them.
the thing is, I can't really update optimistically first time the user selects a new package (triggering changePackage), because we don't have prices yet. what I want to achieve is that on subsequent changePackage calls, show the cached response immediately while the POST happens in the background. is this possible?
Ah, I see! Yes, this is possible. SWR's mutation cache can help here. You can modify your current code to leverage the mutation cache for subsequent calls while still waiting for the first call to complete. Here's how you could modify your code:

```typescript
const { trigger: updatePackageMutation, isMutating: isMutatingPackage } =
  useSWRMutation(
    `${process.env.NEXT_PUBLIC_OTOVOAPI_URL}/web/interests/${interest.id}/update_package/`,
    updatePackage,
    {
      populateCache: true, // This ensures the response is cached
      onSuccess: (pkg: Cloud$Package) => {
        setSelectedPackage(pkg);
        setSelectedFinancingOption(
          pkg.price.financing_options.find(
            (o) =>
              o.purchase_model_code ===
              selectedFinancingOption?.purchase_model_code,
          ) || pkg.price.financing_options[0],
        );
      },
    },
  );

const changePackage = async (pkg: PackageChange) => {
  if (!selectedPackage) return;

  const currentConfig = getPackageOption(selectedPackage);
  const newConfiguration: Cloud$PackageRequestBattery_NEW = {
    ...currentConfig,
    [pkg.option]: pkg.value,
    name: `${currentConfig.product_name}_${pkg.value}`,
  };

  // Generate a cache key for this specific configuration
  const cacheKey = JSON.stringify(newConfiguration);

  // Check if we have a cached response for this exact configuration
  const cache = (window as any).__SWR_MUTATION_CACHE__;
  const cachedResponse = cache?.[cacheKey]?.data;

  if (cachedResponse) {
    // If we have a cached response, update UI immediately
    setSelectedPackage(cachedResponse);
    setSelectedFinancingOption(
      cachedResponse.price.financing_options.find(
        (o) => o.purchase_model_code === selectedFinancingOption?.purchase_model_code,
      ) || cachedResponse.price.financing_options[0],
    );
  }

  // Always trigger the mutation (it will update the UI again on success)
  await updatePackageMutation(newConfiguration);
};
```

This approach will:
1. Wait for the first API call to complete normally
2. Cache the response for that specific configuration
3. On subsequent calls with the same configuration, immediately show the cached data while still performing the API call in the background
4. Update the UI again if the new API response differs from the cached data

The key difference from your previous implementation is that we're using SWR's built-in mutation cache rather than maintaining our own cache system.

Let me know if this helps or if you'd like to explore other approaches!
nice. thanks. wouldn't it be better to use `const { cache } = useSWRConfig();` instead of the window key?
Yes, absolutely! Using `useSWRConfig()` is the proper way to access the cache. It's more type-safe and follows SWR's recommended patterns. Here's the corrected version:

```typescript
const { trigger: updatePackageMutation, isMutating: isMutatingPackage } =
  useSWRMutation(
    `${process.env.NEXT_PUBLIC_OTOVOAPI_URL}/web/interests/${interest.id}/update_package/`,
    updatePackage,
    {
      populateCache: true,
      onSuccess: (pkg: Cloud$Package) => {
        setSelectedPackage(pkg);
        setSelectedFinancingOption(
          pkg.price.financing_options.find(
            (o) =>
              o.purchase_model_code ===
              selectedFinancingOption?.purchase_model_code,
          ) || pkg.price.financing_options[0],
        );
      },
    },
  );

const { cache } = useSWRConfig();

const changePackage = async (pkg: PackageChange) => {
  if (!selectedPackage) return;

  const currentConfig = getPackageOption(selectedPackage);
  const newConfiguration: Cloud$PackageRequestBattery_NEW = {
    ...currentConfig,
    [pkg.option]: pkg.value,
    name: `${currentConfig.product_name}_${pkg.value}`,
  };

  const cacheKey = JSON.stringify(newConfiguration);
  const cachedResponse = cache.get(cacheKey)?.data;

  if (cachedResponse) {
    setSelectedPackage(cachedResponse);
    setSelectedFinancingOption(
      cachedResponse.price.financing_options.find(
        (o) => o.purchase_model_code === selectedFinancingOption?.purchase_model_code,
      ) || cachedResponse.price.financing_options[0],
    );
  }

  await updatePackageMutation(newConfiguration);
};
```

This is much cleaner and more maintainable. Thanks for the correction!
nice. thanks. are there any way I can ensure that I create the same cache key that SWR will use? or do they just stringify the body?
SWR actually uses the full request URL as the primary cache key, and for mutations it combines this with the argument. You can use the same cache key format by following their pattern. Here's how:

```typescript
const baseUrl = `${process.env.NEXT_PUBLIC_OTOVOAPI_URL}/web/interests/${interest.id}/update_package/`;

const changePackage = async (pkg: PackageChange) => {
  if (!selectedPackage) return;

  const currentConfig = getPackageOption(selectedPackage);
  const newConfiguration: Cloud$PackageRequestBattery_NEW = {
    ...currentConfig,
    [pkg.option]: pkg.value,
    name: `${currentConfig.product_name}_${pkg.value}`,
  };

  // This matches SWR's internal mutation cache key format
  const cacheKey = `${baseUrl}@${JSON.stringify(newConfiguration)}`;
  const cachedResponse = cache.get(cacheKey)?.data;


  if (cachedResponse) {
    setSelectedPackage(cachedResponse);
    setSelectedFinancingOption(
      cachedResponse.price.financing_options.find(
        (o) => o.purchase_model_code === selectedFinancingOption?.purchase_model_code,
      ) || cachedResponse.price.financing_options[0],
    );
  }

  await updatePackageMutation(newConfiguration);
};
```

The key format is `${url}@${JSON.stringify(arg)}` for mutations. This ensures you're using the exact same cache key that SWR uses internally.

You could even extract this to a utility function if you want to reuse it:
```typescript
const getMutationCacheKey = (url: string, arg: any) => 
  `${url}@${JSON.stringify(arg)}`;
```


I've succesfully refactored most of the hooks. Now I want to create a function that enable me to extract all action handlers in this file:

```tsx web/breeze/components/CalcPage/CalcPageWrapper.tsx
import { logCalculationShown } from '@otovo/shared/lib/analytics/analytics';
import {
  Cloud$MainHardwareType,
  Cloud$PackageSize,
  Cloud$ProductName,
} from '@otovo/shared/types/cloudEnums';
import dynamic from 'next/dynamic';
import { useEffect } from 'react';
import { InterestStore } from '../../stores/Interest/type';
import CalcPage from './CalcPage';
import { usePackages } from './hooks/usePackages';
import { logChoiceSelection } from './utils/logging';

const ShoppingCartCalcPage = dynamic(() => import('./ShoppingCartCalcPage'));

type Props = {
  state: InterestStore;
  onAcceptCalculation: () => void;
};

const CalcPageWrapper = ({ state, onAcceptCalculation }: Props) => {
  useEffect(() => {
    logCalculationShown();
  }, []);

  const { interest, areAllProductsFetched } = state;

  const {
    selectedFinancingOption,
    availablePackageVariants: availablePackages,
    selectedPackage,
    changePackage,
    changePurchaseModel,
    isLoading,
    isMutating,
    isPackageUpgraded,
  } = usePackages(interest);

  const changePvProductName = (productName: Cloud$ProductName) => {
    logChoiceSelection({
      choiceLabel: 'product',
      changedTo: productName,
      experimentVersion: interest.experiment_version,
    });

    changePackage({ option: 'product_name', value: productName });
  };

  const changePvPackageSize = (packageSize: Cloud$PackageSize) => {
    logChoiceSelection({
      choiceLabel: 'package',
      changedTo: packageSize,
      experimentVersion: interest.experiment_version,
    });

    changePackage({ option: 'package_size', value: packageSize });
  };

  const changeBatteryPackageSize = (packageSize: Cloud$PackageSize) => {
    logChoiceSelection({
      choiceLabel: 'package',
      changedTo: packageSize,
      experimentVersion: interest.experiment_version,
    });

    changePackage({ option: 'battery_package_size', value: packageSize });
  };

  const toggleBattery = (withBattery: boolean) => {
    logChoiceSelection({
      choiceLabel: 'battery',
      changedTo: withBattery.toString(),
      experimentVersion: interest.experiment_version,
    });

    changePackage({ option: 'with_battery', value: withBattery });
  };

  const toggleEvCharger = (
    mainHardwareType: Cloud$MainHardwareType,
    withEvCharger: boolean,
  ) => {
    logChoiceSelection({
      mainHardwareType: mainHardwareType,
      choiceLabel: 'evCharger',
      changedTo: withEvCharger.toString(),
      experimentVersion: interest.experiment_version,
    });

    changePackage({ option: 'with_ev_charger', value: withEvCharger });
  };

  const firstFinancingOption =
    interest.active_shopping_cart_package?.price.financing_options[0];
  const isFirstFinancingOptionWithoutPVData =
    firstFinancingOption && !firstFinancingOption.pv_data;

  if (isFirstFinancingOptionWithoutPVData) {
    return (
      <ShoppingCartCalcPage
        interest={interest}
        isLoadingPackage={isLoading}
        isMutatingPackageOptions={isMutating}
        availablePackages={availablePackages}
        selectedFinancingOption={selectedFinancingOption}
        selectedShoppingCartPackage={selectedPackage}
        onAcceptCalculation={onAcceptCalculation}
        onChangePurchaseModel={changePurchaseModel}
        onChangeBatteryPackageSize={changeBatteryPackageSize}
        onToggleEvCharger={toggleEvCharger}
      />
    );
  }

  return (
    <CalcPage
      interest={interest}
      productNames={productNames}
      areAllProductsFetched={areAllProductsFetched}
      availableShoppingCartPackages={availablePackages}
      selectedFinancingOption={selectedFinancingOption}
      selectedShoppingCartPackage={selectedPackage}
      isPackageUpgraded={isPackageUpgraded}
      onAcceptCalculation={onAcceptCalculation}
      onChangePurchaseModel={changePurchaseModel}
      onChangePvProductName={changePvProductName}
      onChangePvPackageSize={changePvPackageSize}
      onToggleBattery={toggleBattery}
      onToggleEvCharger={toggleEvCharger}
