```typescript
type BaseHandlerConfig<T extends (...args: any[]) => void> = {
  changePackage: (change: PackageChange) => Promise<void>;
  experimentVersion: string;
  handlerFunction: T;
  option: PackageChange['option'];
  choiceLabel: string;
  valueTransform?: (value: Parameters<T>[0]) => string;
};

export function createPackageChangeHandler<T extends (...args: any[]) => void>({
  changePackage,
  experimentVersion,
  handlerFunction,
  option,
  choiceLabel,
  valueTransform = (value) => value.toString(),
}: BaseHandlerConfig<T>): T {
  return ((...args: Parameters<T>) => {
    const value = args[0];

    logChoiceSelection({
      choiceLabel,
      changedTo: valueTransform(value),
      experimentVersion,
      ...(args.length > 1 && { mainHardwareType: args[1] }), // Special case for toggleEvCharger
    });

    changePackage({ option, value });
  }) as T;
}

