```typescript
type PackageChangeHandlerPV = (change: PackageChange) => Promise<void>;
type PackageChangeHandlerBattery = (change: PackageChangeBattery) => Promise<void>;

interface BaseCalcPageActions {
  logChoice: (choiceLabel: string, value: string) => void;
}

interface PVCalcPageActions extends BaseCalcPageActions {
  changePvProductName: (change: { option: 'product_name', value: Cloud$ProductName }) => void;
  changePvPackageSize: (change: { option: 'package_size', value: Cloud$PackageSize }) => void;
  toggleBattery: (change: { option: 'with_battery', value: boolean }) => void;
  toggleEvCharger: (change: { option: 'with_ev_charger', value: boolean }) => void;
}

interface BatteryCalcPageActions extends BaseCalcPageActions {
  changeBatteryPackageSize: (change: { option: 'battery_package_size', value: Cloud$PackageSize }) => void;
  toggleEvCharger: (change: { option: 'with_ev_charger', value: boolean }) => void;
}

function createCalcPageActions(handler: PackageChangeHandlerPV, experimentVersion: string): PVCalcPageActions;
function createCalcPageActions(handler: PackageChangeHandlerBattery, experimentVersion: string): BatteryCalcPageActions;
function createCalcPageActions(
  handler: PackageChangeHandlerPV | PackageChangeHandlerBattery, 
  experimentVersion: string
): PVCalcPageActions | BatteryCalcPageActions {
  const logChoice = (choiceLabel: string, value: string) => {
    logChoiceSelection({
      choiceLabel,
      changedTo: value,
      experimentVersion,
    });
  };

  if ('battery_package_size' in handler) {
    return {
      logChoice,
      changeBatteryPackageSize: (change) => {
        logChoice('package', change.value);
        handler(change);
      },
      toggleEvCharger: (change) => {
        logChoice('evCharger', change.value.toString());
        handler(change);
      },
    };
  }

  return {
    logChoice,
    changePvProductName: (change) => {
      logChoice('product', change.value);
      handler(change);
    },
    changePvPackageSize: (change) => {
      logChoice('package', change.value);
      handler(change);
    },
    toggleBattery: (change) => {
      logChoice('battery', change.value.toString());
      handler(change);
    },
    toggleEvCharger: (change) => {
      logChoice('evCharger', change.value.toString());
      handler(change);
    },
  };
}

